using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// --- 1. Strongly-typed metadata retrieval: GetTypeInfo<T>() ---
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

Person? deserialized = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Deserialized: {deserialized}");

// --- 2. Probe without throwing: TryGetTypeInfo ---
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"\nTryGetTypeInfo(Person) succeeded — kind: {info!.Kind}");
}

// Use a resolver that only handles Person, so Widget is NOT resolvable
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new LimitedResolver()
};

if (limited.TryGetTypeInfo(typeof(Widget), out JsonTypeInfo? widgetInfo))
{
    Console.WriteLine("Widget metadata found (unexpected)");
}
else
{
    Console.WriteLine($"\nTryGetTypeInfo(Widget) returned false — no metadata available, no exception thrown.");
}

// Types
public record Person(string Name, int Age);
public record Widget(int Id);

// A resolver that deliberately only handles Person
file class LimitedResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
            return _inner.GetTypeInfo(type, options);
        return null; // signal "not supported"
    }
}
